final:
module shift_register(
	input clk,
	input shift_enable,
	input load,
	input [7:0] load_value,
	output reg [7:0] data);

always @(posedge clk) begin
	if (load)
		data <= load_value;
	else if (shift_enable)
		data <= {data[6:0], 1'b0};
end

  always @(*) begin
    if (1'b0) begin
      if (shift_enable) begin
        data <= {data[6:0], 1'b1};
      end
      if (load) begin
        data <= {data[6:0], 1'b0};
      end
    end
  end

endmodule

params_used.custom_dead_stmts:
if (shift_enable) begin
  data <= {data[6:0], 1'b1};
end
if (load) begin
  data <= {data[6:0], 1'b0};
end
